import { motion } from 'framer-motion';
import { X, AlertCircle, CheckCircle2, FileCode, Paperclip, FileText, Image, File, Trash2, Plus, MessageSquare } from 'lucide-react';
import { usePlanStore, FileAttachment } from '@/stores/plan-store';
import { DynamicFieldInput } from './DynamicFieldInput';
import { BranchSelector } from './BranchSelector';
import { clsx } from 'clsx';
import { useState, useRef } from 'react';

// Helper to determine file type from extension
function getFileType(filename: string): FileAttachment['type'] {
  const ext = filename.split('.').pop()?.toLowerCase() || '';
  if (['png', 'jpg', 'jpeg', 'gif', 'webp', 'svg', 'bmp'].includes(ext)) return 'image';
  if (['js', 'ts', 'tsx', 'jsx', 'py', 'go', 'rs', 'java', 'c', 'cpp', 'h', 'css', 'html', 'json', 'yaml', 'yml', 'toml', 'md'].includes(ext)) return 'code';
  if (['pdf', 'doc', 'docx', 'txt', 'rtf', 'xls', 'xlsx'].includes(ext)) return 'document';
  return 'other';
}

// File type icon component
function FileTypeIcon({ type }: { type: FileAttachment['type'] }) {
  switch (type) {
    case 'image': return <Image className="w-3 h-3 text-accent-purple" />;
    case 'code': return <FileCode className="w-3 h-3 text-accent-blue" />;
    case 'document': return <FileText className="w-3 h-3 text-accent-yellow" />;
    default: return <File className="w-3 h-3 text-text-muted" />;
  }
}

export function NodeDetailPanel() {
  const { nodes, selectedNodeId, setSelectedNodeId, updateFieldValue, setSelectedBranch, addAttachment, removeAttachment, updateMetaInstructions } = usePlanStore();
  const [newFilePath, setNewFilePath] = useState('');
  const inputRef = useRef<HTMLInputElement>(null);

  const node = nodes.find((n) => n.id === selectedNodeId);

  if (!node) return null;

  const requiredFieldsEmpty = node.dynamicFields.filter(
    (f) => f.required && !f.value
  ).length;

  const handleFieldChange = (fieldId: string, value: string) => {
    updateFieldValue(node.id, fieldId, value);
  };

  const handleBranchSelect = (branchId: string) => {
    setSelectedBranch(node.id, branchId);
  };

  const handleAddFile = () => {
    if (!newFilePath.trim()) return;
    const name = newFilePath.split('/').pop() || newFilePath;
    const attachment: FileAttachment = {
      id: `att_${Date.now()}`,
      path: newFilePath.trim(),
      name,
      type: getFileType(name),
    };
    addAttachment(node.id, attachment);
    setNewFilePath('');
  };

  const handleKeyDown = (e: React.KeyboardEvent) => {
    if (e.key === 'Enter') {
      e.preventDefault();
      handleAddFile();
    }
  };

  return (
    <motion.div
      initial={{ x: 400, opacity: 0 }}
      animate={{ x: 0, opacity: 1 }}
      exit={{ x: 400, opacity: 0 }}
      transition={{ type: 'spring', stiffness: 300, damping: 30 }}
      className="absolute top-0 right-0 h-full w-[360px] bg-surface/95 backdrop-blur-md border-l border-border shadow-2xl overflow-hidden flex flex-col"
    >
      {/* Header - Compact */}
      <div className="px-3 py-2.5 border-b border-border flex items-start justify-between">
        <div className="flex-1 min-w-0">
          <div className="flex items-center gap-1.5 mb-0.5">
            <span
              className={clsx('w-1.5 h-1.5 rounded-full', {
                'bg-status-pending': node.status === 'pending',
                'bg-status-active animate-pulse': node.status === 'active',
                'bg-status-completed': node.status === 'completed',
                'bg-status-failed': node.status === 'failed',
              })}
            />
            <span className="text-[10px] text-text-muted capitalize">
              {node.type} · {node.status}
            </span>
          </div>
          <h2 className="text-sm font-semibold text-text-primary truncate">
            {node.title}
          </h2>
        </div>

        <button
          onClick={() => setSelectedNodeId(null)}
          className="p-1 rounded hover:bg-surface-raised text-text-muted hover:text-text-primary transition-colors"
        >
          <X className="w-3.5 h-3.5" />
        </button>
      </div>

      {/* Content - Scrollable */}
      <div className="flex-1 overflow-y-auto px-3 py-2 space-y-3">
        {/* Description */}
        {node.description && (
          <section>
            <h3 className="text-[10px] font-medium text-text-muted uppercase tracking-wider mb-1">
              Description
            </h3>
            <p className="text-xs text-text-secondary leading-relaxed">
              {node.description}
            </p>
          </section>
        )}

        {/* Metadata Grid - More compact */}
        <section className="grid grid-cols-2 gap-2">
          {node.complexity && (
            <div className="p-2 rounded-md bg-surface-raised">
              <span className="text-[9px] text-text-muted uppercase tracking-wider">
                Complexity
              </span>
              <p
                className={clsx('text-xs font-medium', {
                  'text-accent-green': node.complexity === 'low',
                  'text-accent-yellow': node.complexity === 'medium',
                  'text-accent-red': node.complexity === 'high',
                })}
              >
                {node.complexity}
              </p>
            </div>
          )}

          {node.expectedOutput && (
            <div className="p-2 rounded-md bg-surface-raised col-span-2">
              <span className="text-[9px] text-text-muted uppercase tracking-wider flex items-center gap-1">
                <FileCode className="w-2.5 h-2.5" />
                Expected Output
              </span>
              <p className="text-xs text-text-secondary mt-0.5">
                {node.expectedOutput}
              </p>
            </div>
          )}
        </section>

        {/* Risks */}
        {node.risks && (
          <section>
            <h3 className="text-[10px] font-medium text-text-muted uppercase tracking-wider mb-1 flex items-center gap-1">
              <AlertCircle className="w-2.5 h-2.5" />
              Risks
            </h3>
            <p className="text-xs text-text-secondary bg-accent-yellow/5 border border-accent-yellow/20 rounded-md p-2">
              {node.risks}
            </p>
          </section>
        )}

        {/* Branches (for decision nodes) */}
        {node.type === 'decision' && node.branches && (
          <section>
            <h3 className="text-[10px] font-medium text-text-muted uppercase tracking-wider mb-2">
              Choose a Path
            </h3>
            <BranchSelector
              branches={node.branches}
              selectedBranchId={node.selectedBranchId}
              onSelect={handleBranchSelect}
            />
          </section>
        )}

        {/* Dynamic Fields */}
        {node.dynamicFields.length > 0 && (
          <section>
            <h3 className="text-[10px] font-medium text-text-muted uppercase tracking-wider mb-2">
              Configuration
              {requiredFieldsEmpty > 0 && (
                <span className="ml-1.5 text-accent-yellow">
                  ({requiredFieldsEmpty} required)
                </span>
              )}
            </h3>
            <div className="space-y-2.5">
              {node.dynamicFields.map((field) => (
                <DynamicFieldInput
                  key={field.id}
                  field={field}
                  onChange={(value) => handleFieldChange(field.id, value)}
                />
              ))}
            </div>
          </section>
        )}

        {/* File Attachments */}
        <section>
          <h3 className="text-[10px] font-medium text-text-muted uppercase tracking-wider mb-2 flex items-center gap-1">
            <Paperclip className="w-2.5 h-2.5" />
            File Attachments
          </h3>

          {/* Existing attachments */}
          {node.attachments.length > 0 && (
            <div className="space-y-1 mb-2">
              {node.attachments.map((att) => (
                <div
                  key={att.id}
                  className="flex items-center gap-2 p-1.5 rounded-md bg-surface-raised group"
                >
                  <FileTypeIcon type={att.type} />
                  <div className="flex-1 min-w-0">
                    <p className="text-xs text-text-primary truncate">{att.name}</p>
                    <p className="text-[10px] text-text-muted truncate">{att.path}</p>
                  </div>
                  <button
                    onClick={() => removeAttachment(node.id, att.id)}
                    className="p-1 rounded opacity-0 group-hover:opacity-100 hover:bg-accent-red/20 text-text-muted hover:text-accent-red transition-all"
                  >
                    <Trash2 className="w-3 h-3" />
                  </button>
                </div>
              ))}
            </div>
          )}

          {/* Add file input */}
          <div className="flex gap-1.5">
            <input
              ref={inputRef}
              type="text"
              value={newFilePath}
              onChange={(e) => setNewFilePath(e.target.value)}
              onKeyDown={handleKeyDown}
              placeholder="Enter file path..."
              className="flex-1 px-2 py-1.5 rounded-md bg-canvas border border-border text-xs text-text-primary placeholder-text-muted focus:outline-none focus:ring-1 focus:ring-accent-blue"
            />
            <button
              onClick={handleAddFile}
              disabled={!newFilePath.trim()}
              className="px-2 py-1.5 rounded-md bg-accent-blue/20 text-accent-blue hover:bg-accent-blue/30 disabled:opacity-50 disabled:cursor-not-allowed transition-colors"
            >
              <Plus className="w-3.5 h-3.5" />
            </button>
          </div>
          <p className="text-[10px] text-text-muted mt-1">
            Add file paths for the AI to reference
          </p>
        </section>

        {/* Meta Instructions */}
        <section>
          <h3 className="text-[10px] font-medium text-text-muted uppercase tracking-wider mb-2 flex items-center gap-1">
            <MessageSquare className="w-2.5 h-2.5" />
            Instructions for AI
          </h3>
          <textarea
            value={node.metaInstructions || ''}
            onChange={(e) => updateMetaInstructions(node.id, e.target.value)}
            placeholder="Add specific instructions for this step..."
            rows={3}
            className="w-full px-2 py-1.5 rounded-md bg-canvas border border-border text-xs text-text-primary placeholder-text-muted focus:outline-none focus:ring-1 focus:ring-accent-blue resize-none"
          />
          <p className="text-[10px] text-text-muted mt-1">
            These instructions will be sent to the AI when executing this node
          </p>
        </section>

        {/* Execution Output */}
        {node.output && (
          <section>
            <h3 className="text-[10px] font-medium text-text-muted uppercase tracking-wider mb-1 flex items-center gap-1">
              <CheckCircle2 className="w-2.5 h-2.5 text-accent-green" />
              Output
            </h3>
            <pre className="text-[10px] text-text-secondary bg-canvas rounded-md p-2 overflow-x-auto font-mono max-h-32">
              {node.output}
            </pre>
          </section>
        )}
      </div>

      {/* Footer - Compact */}
      <div className="px-3 py-2 border-t border-border bg-surface">
        <div className="flex items-center justify-between text-[10px] text-text-muted">
          <span>ID: {node.id}</span>
          <span>
            {node.attachments.length > 0 && `${node.attachments.length} files`}
            {node.attachments.length > 0 && node.metaInstructions && ' · '}
            {node.metaInstructions && 'Has instructions'}
          </span>
        </div>
      </div>
    </motion.div>
  );
}
