import { useEffect } from 'react';
import { ReactFlowProvider } from '@xyflow/react';
import '@xyflow/react/dist/style.css';
import { PlanCanvas } from './components/Canvas/PlanCanvas';
import { Header } from './components/Layout/Header';
import { Footer } from './components/Layout/Footer';
import { NodeDetailPanel } from './components/Panel/NodeDetailPanel';
import { ApproveButton } from './components/Controls/ApproveButton';
import { usePlanStore } from './stores/plan-store';
import { useWebSocket } from './hooks/useWebSocket';

function App() {
  const { selectedNodeId, plan, canApprove } = usePlanStore();
  const { approvePlan } = useWebSocket();

  // Keyboard shortcut for approval
  useEffect(() => {
    const handleKeyDown = (e: KeyboardEvent) => {
      if (e.key === 'Enter' && plan?.status === 'ready' && canApprove()) {
        e.preventDefault();
        approvePlan();
      }
      if (e.key === 'Escape') {
        usePlanStore.getState().setSelectedNodeId(null);
      }
    };

    window.addEventListener('keydown', handleKeyDown);
    return () => window.removeEventListener('keydown', handleKeyDown);
  }, [plan, canApprove, approvePlan]);

  return (
    <div className="h-screen w-screen flex flex-col overflow-hidden bg-canvas">
      <Header />

      <main className="flex-1 relative">
        <ReactFlowProvider>
          <PlanCanvas />
        </ReactFlowProvider>

        {/* Approve button */}
        <ApproveButton />

        {/* Side panel for node details */}
        {selectedNodeId && <NodeDetailPanel />}
      </main>

      <Footer />
    </div>
  );
}

export default App;
