import { memo } from 'react';
import { Handle, Position } from '@xyflow/react';
import { motion } from 'framer-motion';
import type { PlanNode, Branch } from '@/stores/plan-store';
import { GitBranch, Check } from 'lucide-react';
import { clsx } from 'clsx';

interface DecisionNodeProps {
  data: PlanNode;
  selected?: boolean;
}

export const DecisionNode = memo(function DecisionNode({ data, selected }: DecisionNodeProps) {
  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.8, y: 20 }}
      animate={{ opacity: 1, scale: 1, y: 0 }}
      transition={{
        type: 'spring',
        stiffness: 300,
        damping: 25,
      }}
      className={clsx(
        'px-4 py-3 rounded-xl min-w-[240px] max-w-[320px]',
        'bg-gradient-to-br from-accent-purple/10 to-accent-blue/10',
        'backdrop-blur-sm',
        'border-2 transition-all duration-200',
        {
          'border-accent-purple/30 hover:border-accent-purple/50': !selected,
          'ring-2 ring-accent-purple ring-offset-2 ring-offset-canvas': selected,
        }
      )}
    >
      {/* Top handle */}
      <Handle
        type="target"
        position={Position.Top}
        className="!w-3 !h-3 !bg-accent-purple !border-2 !border-surface"
      />

      {/* Header */}
      <div className="flex items-center gap-2 mb-3">
        <div className="p-1.5 rounded-lg bg-accent-purple/20">
          <GitBranch className="w-4 h-4 text-accent-purple" />
        </div>
        <div>
          <h3 className="font-medium text-sm text-text-primary">
            {data.title}
          </h3>
          <p className="text-[10px] text-text-muted">Choose a path</p>
        </div>
      </div>

      {/* Branches */}
      {data.branches && (
        <div className="space-y-2">
          {data.branches.map((branch: Branch) => (
            <div
              key={branch.id}
              className={clsx(
                'px-3 py-2 rounded-lg border transition-all cursor-pointer',
                {
                  'border-accent-green bg-accent-green/10':
                    data.selectedBranchId === branch.id,
                  'border-border hover:border-border-subtle bg-surface/50':
                    data.selectedBranchId !== branch.id,
                }
              )}
            >
              <div className="flex items-center justify-between">
                <span className="text-xs font-medium text-text-primary">
                  {branch.label}
                </span>
                {data.selectedBranchId === branch.id && (
                  <Check className="w-3 h-3 text-accent-green" />
                )}
              </div>
              {branch.description && (
                <p className="text-[10px] text-text-muted mt-1 line-clamp-2">
                  {branch.description}
                </p>
              )}
            </div>
          ))}
        </div>
      )}

      {/* Status indicator */}
      {!data.selectedBranchId && data.branches && data.branches.length > 0 && (
        <div className="mt-3 pt-2 border-t border-border">
          <span className="text-[10px] text-accent-yellow">
            Selection required
          </span>
        </div>
      )}

      {/* Bottom handle */}
      <Handle
        type="source"
        position={Position.Bottom}
        className="!w-3 !h-3 !bg-accent-purple !border-2 !border-surface"
      />
    </motion.div>
  );
});
