import { memo } from 'react';
import { Handle, Position } from '@xyflow/react';
import { motion } from 'framer-motion';
import type { PlanNode, NodeStatus } from '@/stores/plan-store';
import { CheckCircle2, Circle, Loader2, XCircle, SkipForward, type LucideIcon } from 'lucide-react';
import { clsx } from 'clsx';

interface TaskNodeProps {
  data: PlanNode;
  selected?: boolean;
}

const statusIcons: Record<NodeStatus, LucideIcon> = {
  pending: Circle,
  active: Loader2,
  completed: CheckCircle2,
  failed: XCircle,
  skipped: SkipForward,
};

const complexityColors: Record<string, string> = {
  low: 'bg-accent-green/10 text-accent-green',
  medium: 'bg-accent-yellow/10 text-accent-yellow',
  high: 'bg-accent-red/10 text-accent-red',
};

export const TaskNode = memo(function TaskNode({ data, selected }: TaskNodeProps) {
  const StatusIcon = statusIcons[data.status];

  return (
    <motion.div
      initial={{ opacity: 0, scale: 0.8, y: 20 }}
      animate={{ opacity: 1, scale: 1, y: 0 }}
      transition={{
        type: 'spring',
        stiffness: 300,
        damping: 25,
      }}
      className={clsx(
        'px-4 py-3 rounded-xl min-w-[200px] max-w-[280px]',
        'bg-surface/80 backdrop-blur-sm',
        'border-2 transition-all duration-200',
        {
          'border-border hover:border-border-subtle': data.status === 'pending',
          'border-status-active shadow-glow-yellow': data.status === 'active',
          'border-status-completed shadow-glow-green': data.status === 'completed',
          'border-status-failed shadow-glow-red': data.status === 'failed',
          'border-border opacity-50': data.status === 'skipped',
          'ring-2 ring-accent-blue ring-offset-2 ring-offset-canvas': selected,
        }
      )}
    >
      {/* Top handle */}
      <Handle
        type="target"
        position={Position.Top}
        className="!w-3 !h-3 !bg-border !border-2 !border-surface"
      />

      {/* Header */}
      <div className="flex items-start gap-3">
        <div
          className={clsx('mt-0.5', {
            'text-text-muted': data.status === 'pending' || data.status === 'skipped',
            'text-status-active animate-spin': data.status === 'active',
            'text-status-completed': data.status === 'completed',
            'text-status-failed': data.status === 'failed',
          })}
        >
          <StatusIcon className="w-4 h-4" />
        </div>

        <div className="flex-1 min-w-0">
          <h3 className="font-medium text-sm text-text-primary truncate">
            {data.title}
          </h3>

          {data.description && (
            <p className="text-xs text-text-muted mt-1 line-clamp-2">
              {data.description}
            </p>
          )}
        </div>
      </div>

      {/* Footer */}
      <div className="flex items-center gap-2 mt-3 pt-2 border-t border-border">
        {data.complexity && (
          <span
            className={clsx(
              'text-[10px] font-medium px-1.5 py-0.5 rounded',
              complexityColors[data.complexity]
            )}
          >
            {data.complexity}
          </span>
        )}

        {data.dynamicFields && data.dynamicFields.length > 0 && (
          <span className="text-[10px] text-text-muted">
            {data.dynamicFields.filter((f) => f.required && !f.value).length > 0
              ? `${data.dynamicFields.filter((f) => f.required && !f.value).length} fields required`
              : `${data.dynamicFields.length} fields`}
          </span>
        )}
      </div>

      {/* Active indicator pulse */}
      {data.status === 'active' && (
        <motion.div
          className="absolute inset-0 rounded-xl border-2 border-status-active"
          initial={{ opacity: 0.5 }}
          animate={{ opacity: [0.5, 0.2, 0.5] }}
          transition={{ duration: 2, repeat: Infinity }}
        />
      )}

      {/* Bottom handle */}
      <Handle
        type="source"
        position={Position.Bottom}
        className="!w-3 !h-3 !bg-border !border-2 !border-surface"
      />
    </motion.div>
  );
});
