import { useCallback, useEffect } from 'react';
import {
  ReactFlow,
  Background,
  Controls,
  MiniMap,
  useNodesState,
  useEdgesState,
  BackgroundVariant,
  ConnectionMode,
  type Node,
  type Edge,
  type NodeTypes,
} from '@xyflow/react';
import { usePlanStore, type PlanNode } from '@/stores/plan-store';
import { TaskNode } from './TaskNode';
import { DecisionNode } from './DecisionNode';
import { useAutoLayout } from '@/hooks/useAutoLayout';
import { AnimatePresence } from 'framer-motion';

// Register custom node types - use any to bypass strict typing
// eslint-disable-next-line @typescript-eslint/no-explicit-any
const nodeTypes: NodeTypes = {
  task: TaskNode,
  decision: DecisionNode,
} as any;

export function PlanCanvas() {
  const { nodes: planNodes, edges: planEdges, setSelectedNodeId, plan } = usePlanStore();
  const [nodes, setNodes, onNodesChange] = useNodesState([]);
  const [edges, setEdges, onEdgesChange] = useEdgesState([]);

  // Auto-layout hook
  const { layoutNodes } = useAutoLayout();

  // Convert plan nodes to ReactFlow nodes
  useEffect(() => {
    const rfNodes = planNodes.map((node: PlanNode) => ({
      id: node.id,
      type: node.type,
      position: { x: 0, y: 0 },
      data: node,
    }));

    const rfEdges = planEdges.map((edge) => ({
      id: edge.id,
      source: edge.from,
      target: edge.to,
      animated: planNodes.find((n) => n.id === edge.from)?.status === 'active',
      style: {
        stroke: '#3f3f46',
        strokeWidth: 2,
      },
    }));

    // Apply auto-layout
    const layoutedNodes = layoutNodes(rfNodes as unknown as Node[], rfEdges as unknown as Edge[]);
    setNodes(layoutedNodes as unknown as never[]);
    setEdges(rfEdges as unknown as never[]);
  }, [planNodes, planEdges, layoutNodes, setNodes, setEdges]);

  const onNodeClick = useCallback(
    (_: React.MouseEvent, node: Node) => {
      setSelectedNodeId(node.id);
    },
    [setSelectedNodeId]
  );

  const onPaneClick = useCallback(() => {
    setSelectedNodeId(null);
  }, [setSelectedNodeId]);

  return (
    <div className="w-full h-full">
      <AnimatePresence>
        <ReactFlow
          nodes={nodes}
          edges={edges}
          onNodesChange={onNodesChange}
          onEdgesChange={onEdgesChange}
          onNodeClick={onNodeClick}
          onPaneClick={onPaneClick}
          nodeTypes={nodeTypes}
          connectionMode={ConnectionMode.Loose}
          fitView
          fitViewOptions={{
            padding: 0.2,
            maxZoom: 1.5,
          }}
          minZoom={0.1}
          maxZoom={2}
          defaultEdgeOptions={{
            type: 'smoothstep',
          }}
        >
          <Background
            variant={BackgroundVariant.Dots}
            gap={20}
            size={1}
            color="#27272a"
          />
          <Controls
            showInteractive={false}
            className="!bg-surface !border-border !rounded-lg"
          />
          <MiniMap
            nodeColor={(node) => {
              const data = node.data as unknown as PlanNode | undefined;
              const status = data?.status;
              switch (status) {
                case 'completed':
                  return '#22c55e';
                case 'active':
                  return '#eab308';
                case 'failed':
                  return '#ef4444';
                default:
                  return '#3f3f46';
              }
            }}
            maskColor="rgba(10, 10, 11, 0.8)"
            className="!bg-surface/80 !border-border !rounded-lg"
          />
        </ReactFlow>
      </AnimatePresence>

      {/* Empty state */}
      {!plan && (
        <div className="absolute inset-0 flex items-center justify-center pointer-events-none">
          <div className="text-center">
            <div className="w-16 h-16 mx-auto mb-4 rounded-2xl bg-surface/50 border border-border flex items-center justify-center">
              <svg
                className="w-8 h-8 text-text-muted"
                fill="none"
                viewBox="0 0 24 24"
                stroke="currentColor"
              >
                <path
                  strokeLinecap="round"
                  strokeLinejoin="round"
                  strokeWidth={1.5}
                  d="M9 17V7m0 10a2 2 0 01-2 2H5a2 2 0 01-2-2V7a2 2 0 012-2h2a2 2 0 012 2m0 10a2 2 0 002 2h2a2 2 0 002-2M9 7a2 2 0 012-2h2a2 2 0 012 2m0 10V7m0 10a2 2 0 002 2h2a2 2 0 002-2V7a2 2 0 00-2-2h-2a2 2 0 00-2 2"
                />
              </svg>
            </div>
            <h3 className="text-lg font-medium text-text-primary mb-2">
              Waiting for plan...
            </h3>
            <p className="text-sm text-text-muted max-w-xs">
              Give your AI agent a task and watch the execution plan appear here in real-time.
            </p>
          </div>
        </div>
      )}
    </div>
  );
}
