import { useEffect, useRef, useCallback } from 'react';
import { usePlanStore, PlanNode, PlanEdge, Plan } from '@/stores/plan-store';

const WS_URL = 'ws://localhost:3030';

type MessageType =
  | { type: 'connected' }
  | { type: 'plan_started'; plan: Plan }
  | { type: 'node_added'; node: PlanNode }
  | { type: 'edge_added'; edge: PlanEdge }
  | { type: 'plan_ready' }
  | { type: 'node_status_updated'; nodeId: string; status: PlanNode['status']; output?: string }
  | { type: 'plan_completed' }
  | { type: 'plan_failed'; error: string }
  | { type: 'error'; message: string };

export function useWebSocket() {
  const wsRef = useRef<WebSocket | null>(null);
  const reconnectTimeoutRef = useRef<number | null>(null);

  const {
    setConnected,
    setPlan,
    addNode,
    addEdge,
    updatePlanStatus,
    updateNodeStatus,
    clearPlan,
  } = usePlanStore();

  const connect = useCallback(() => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      return;
    }

    try {
      const ws = new WebSocket(WS_URL);

      ws.onopen = () => {
        console.log('[Overture] Connected to server');
        setConnected(true);

        // Clear any reconnection timeout
        if (reconnectTimeoutRef.current) {
          clearTimeout(reconnectTimeoutRef.current);
          reconnectTimeoutRef.current = null;
        }
      };

      ws.onclose = () => {
        console.log('[Overture] Disconnected from server');
        setConnected(false);

        // Attempt to reconnect after 3 seconds
        reconnectTimeoutRef.current = window.setTimeout(() => {
          console.log('[Overture] Attempting to reconnect...');
          connect();
        }, 3000);
      };

      ws.onerror = (error) => {
        console.error('[Overture] WebSocket error:', error);
      };

      ws.onmessage = (event) => {
        try {
          const message: MessageType = JSON.parse(event.data);
          handleMessage(message);
        } catch (error) {
          console.error('[Overture] Failed to parse message:', error);
        }
      };

      wsRef.current = ws;
    } catch (error) {
      console.error('[Overture] Failed to connect:', error);
      setConnected(false);
    }
  }, [setConnected]);

  const handleMessage = useCallback(
    (message: MessageType) => {
      switch (message.type) {
        case 'connected':
          console.log('[Overture] Server acknowledged connection');
          break;

        case 'plan_started':
          clearPlan();
          setPlan({ ...message.plan, status: 'streaming' });
          break;

        case 'node_added':
          addNode(message.node);
          break;

        case 'edge_added':
          addEdge(message.edge);
          break;

        case 'plan_ready':
          updatePlanStatus('ready');
          break;

        case 'node_status_updated':
          updateNodeStatus(message.nodeId, message.status, message.output);
          break;

        case 'plan_completed':
          updatePlanStatus('completed');
          break;

        case 'plan_failed':
          updatePlanStatus('failed');
          console.error('[Overture] Plan failed:', message.error);
          break;

        case 'error':
          console.error('[Overture] Server error:', message.message);
          break;

        default:
          console.warn('[Overture] Unknown message type:', message);
      }
    },
    [clearPlan, setPlan, addNode, addEdge, updatePlanStatus, updateNodeStatus]
  );

  const sendMessage = useCallback((message: object) => {
    if (wsRef.current?.readyState === WebSocket.OPEN) {
      wsRef.current.send(JSON.stringify(message));
    } else {
      console.warn('[Overture] Cannot send message - not connected');
    }
  }, []);

  const approvePlan = useCallback(() => {
    const state = usePlanStore.getState();

    // Collect all field values
    const fieldValues: Record<string, string> = {};
    for (const node of state.nodes) {
      for (const field of node.dynamicFields) {
        if (field.value) {
          fieldValues[`${node.id}.${field.name}`] = field.value;
        }
      }
    }

    // Collect selected branches
    const selectedBranches: Record<string, string> = {};
    for (const node of state.nodes) {
      if (node.type === 'decision' && node.selectedBranchId) {
        selectedBranches[node.id] = node.selectedBranchId;
      }
    }

    // Collect node configs (attachments and meta instructions)
    const nodeConfigs: Record<string, {
      fieldValues: Record<string, string>;
      attachments: { id: string; path: string; name: string; type: string }[];
      metaInstructions?: string;
    }> = {};
    for (const node of state.nodes) {
      // Collect field values for this node
      const nodeFieldValues: Record<string, string> = {};
      for (const field of node.dynamicFields) {
        if (field.value) {
          nodeFieldValues[field.name] = field.value;
        }
      }

      // Only include if there's something to send
      if (node.attachments.length > 0 || node.metaInstructions || Object.keys(nodeFieldValues).length > 0) {
        nodeConfigs[node.id] = {
          fieldValues: nodeFieldValues,
          attachments: node.attachments,
          metaInstructions: node.metaInstructions,
        };
      }
    }

    sendMessage({
      type: 'approve_plan',
      fieldValues,
      selectedBranches,
      nodeConfigs,
    });

    usePlanStore.getState().approvePlan();
  }, [sendMessage]);

  // Connect on mount
  useEffect(() => {
    connect();

    return () => {
      if (reconnectTimeoutRef.current) {
        clearTimeout(reconnectTimeoutRef.current);
      }
      wsRef.current?.close();
    };
  }, [connect]);

  return {
    sendMessage,
    approvePlan,
  };
}
